    if 'static bool checkAndReplaceCondition' in line:
        # Find the opening brace
        j = i
        while j < len(lines) and '{' not in lines[j]:
            j += 1
        if j < len(lines):
            # Insert after the brace
            insert_line = j + 1
            check_code = '''  // Check if any use is in an or disjoint instruction.
