    if (auto *BO = dyn_cast<BinaryOperator>(U.getUser())) {
      if (BO->getOpcode() == Instruction::Or && cast<PossiblyDisjointInst>(BO)->isDisjoint()) {
        return false;
      }
    }
  }
'''
